if (!$env.GDA_API_KEY_2026 || !$env.GDA_DEPLOY_KEY_2026 || !$env.GDA_WEBHOOK_SECRET_2026) throw new Error('2026 auth env vars not set');
const headers = $input.first().json.headers || {};
const body = $input.first().json.body || {};
const auth = headers["x-gda-auth"] || headers["x-gda-key"] || body.auth_key || body.deploy_key || "";
const validKeys = [$env.GDA_DEPLOY_KEY_2026, $env.GDA_API_KEY_2026, $env.GDA_WEBHOOK_SECRET_2026];
if (!validKeys.includes(auth)) {
  const origin = (headers.origin || headers.referer || "").toLowerCase();
  const trusted = ["gda.csr-llc.tech","n8n.csr-llc.tech","localhost","gdacommand.retool.com"];
  if (!trusted.some(o => origin.includes(o))) throw new Error("Unauthorized");
}
return [{ json: body }];

const modules = $('Module Counts').all().map(i => i.json).filter(r => r.module);
const topOpps = $('Top Opportunities').all().map(i => i.json).filter(r => r.solicitation_number);
const partners = $('Top Partners').all().map(i => i.json).filter(r => r.company_name);

const summary = {};
for (const m of modules) summary[m.module] = { count: parseInt(m.count) || 0, last_updated: m.last_updated };

const totalRecords = modules.reduce((s, m) => s + (parseInt(m.count) || 0), 0);

return [{ json: {
  status: 'ok',
  capture_hub: {
    total_records: totalRecords,
    pursue_opps: topOpps.filter(o => o.gda_label === 'PURSUE').length,
    evaluate_opps: topOpps.filter(o => o.gda_label === 'EVALUATE').length,
    teaming_partners: partners.length,
    modules: summary,
    top_opportunities: topOpps,
    top_teaming_partners: partners,
    timestamp: new Date().toISOString()
  }
}}];
